bool isPossible(const vector<long long>& C, int A, long long limit) {
    int painters = 1;
    long long total = 0;

    for (auto len : C) {
        if (len > limit) return false;
        if (total + len > limit) {
            painters++;
            total = len;
            if (painters > A) return false;
        } else {
            total += len;
        }
    }
    return true;
}

long long minTime(int A, int B, const vector<long long>& C) {
    const long long mod = 10000003;
    long long low = *max_element(C.begin(), C.end());
    long long high = accumulate(C.begin(), C.end(), 0LL);
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (isPossible(C, A, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return ((ans % mod) * (B % mod)) % mod;
}

