function isPossible(C, A, limit) {
    let painters = 1;
    let total = 0;

    for (let len of C) {
        if (len > limit) return false;
        if (total + len > limit) {
            painters++;
            total = len;
            if (painters > A) return false;
        } else {
            total += len;
        }
    }
    return true;
}

function minTime(A, B, C) {
    const mod = 10000003;
    let low = Math.max(...C);
    let high = C.reduce((a, b) => a + b, 0);
    let ans = high;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (isPossible(C, A, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    // Convert BigInt result back to normal number
    return Number((BigInt(ans % mod) * BigInt(B % mod)) % BigInt(mod));
}
